// Setzt den Demo-Verein bei jedem Laden frisch aus dem Code (korrekte Passwörter etc.).
// Echte Vereine des Nutzers bleiben unverändert erhalten.
function refreshDemo(d) {
  try {
    if(!d || typeof d!=="object") return d;
    const f = seed();
    const notDemo = x => x && x.cid !== "demo";
    const isDemo  = x => x && x.cid === "demo";
    d.clubs          = [...(d.clubs||[]).filter(c=>c&&c.id!=="demo"), ...(f.clubs||[]).filter(c=>c.id==="demo")];
    d.teams          = [...(d.teams||[]).filter(notDemo),          ...(f.teams||[]).filter(isDemo)];
    d.playerProfiles = [...(d.playerProfiles||[]).filter(notDemo), ...(f.playerProfiles||[]).filter(isDemo)];
    d.events         = [...(d.events||[]).filter(notDemo),         ...(f.events||[]).filter(isDemo)];
    d.helpers        = [...(d.helpers||[]).filter(notDemo),        ...(f.helpers||[]).filter(isDemo)];
    d.trainers       = [...(d.trainers||[]).filter(notDemo),       ...(f.trainers||[]).filter(isDemo)];
    d.seasons        = [...(d.seasons||[]).filter(notDemo),        ...(f.seasons||[]).filter(isDemo)];
    // Demo-Turnier dauerhaft fuer Gaeste freischalten: frisches Live-Fenster + Snapshot,
    // damit die Besucher-Ansicht ("Turniere") nie leer ist und man es ohne Passwort ansehen kann.
    const dt = (f.events||[]).find(e=>e.id==="de4");
    if(dt){
      const le = { id:"de4", eid:"de4", clubId:"demo", clubSlug:"demo-verein",
        title:dt.title, date:dt.date,
        from:new Date(Date.now()-3600000).toISOString(),
        until:new Date(Date.now()+30*86400000).toISOString(),
        pub:tournPubSnapshot(dt, (f.playerProfiles||[])) };
      d.liveEvents = [...(d.liveEvents||[]).filter(x=>x && x.eid!=="de4" && x.clubId!=="demo" && x.clubSlug!=="demo-verein"), le];
    }
  } catch {}
  return d;
}

function PushSetupGuide({ onClose }) {
  const [tab, setTab] = useState("ios");
  const tabs = [
    { id:"ios",     label:"iPhone / iPad", icon:"📱" },
    { id:"android", label:"Android",       icon:"🤖" },
    { id:"desktop", label:"Mac / PC",      icon:"💻" },
  ];
  const steps = {
    ios: [
      { t:"Voraussetzung", s:"iOS 16.4 oder neuer. App muss zum Home-Bildschirm hinzugefügt sein – aus dem Safari-Tab raus geht KEIN Push auf iPhone." },
      { t:"App zum Home-Bildschirm", s:"In Safari die App öffnen (verein.bolwerk24.de) → unten Mitte „Teilen“-Symbol → „Zum Home-Bildschirm“." },
      { t:"App vom Home-Bildschirm öffnen", s:"Wichtig: NICHT mehr aus Safari, sondern vom Home-Bildschirm aus tippen." },
      { t:"Benachrichtigungen aktivieren", s:"Unten rechts erscheint ein 🔔-Symbol. Antippen → „Aktivieren“ → iOS fragt nach Berechtigung → erlauben." },
      { t:"Was du dann einstellen kannst", s:"Pro Bereich (Abstimm-Erinnerung 3 Tage vorher, Morgens am Termin-Tag, Chat-Nachrichten) sowie pro Termin-Art (Training/Spiel/…) und pro einzelnem Termin an/aus." },
    ],
    android: [
      { t:"Voraussetzung", s:"Aktueller Chrome (oder Edge/Firefox). App muss nicht installiert sein, kann aber – funktioniert auch im normalen Tab." },
      { t:"App öffnen", s:"verein.bolwerk24.de in Chrome öffnen." },
      { t:"Optional installieren", s:"Adressleiste zeigt ein Installations-Icon (rechts) → „App installieren“. Spart Suchen später." },
      { t:"Benachrichtigungen aktivieren", s:"🔔-Symbol unten rechts → „Aktivieren“ → Chrome-Dialog → erlauben." },
      { t:"Was du dann einstellen kannst", s:"Genau wie auf iPhone: pro Bereich, pro Termin-Art und pro Einzeltermin abschaltbar." },
    ],
    desktop: [
      { t:"Voraussetzung", s:"Chrome, Edge, Firefox oder Safari. macOS: Safari 16+ unterstützt Web-Push seit 2023." },
      { t:"App öffnen", s:"verein.bolwerk24.de im Browser." },
      { t:"Benachrichtigungen aktivieren", s:"🔔-Symbol unten rechts → „Aktivieren“ → Browser fragt nach Berechtigung." },
      { t:"Mac: System-Berechtigung prüfen", s:"Falls keine Benachrichtigung kommt: Systemeinstellungen → Mitteilungen → den Browser auf „Erlauben“ stellen." },
      { t:"Banner-Stil wählen", s:"In den Betriebssystem-Einstellungen kannst du wählen, ob Benachrichtigungen kurz oder dauerhaft eingeblendet werden." },
    ],
  };
  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.75)",
      display:"flex",alignItems:"center",justifyContent:"center",zIndex:9999,padding:18}}>
      <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:20,
        width:"100%",maxWidth:560,maxHeight:"88vh",overflow:"auto",boxShadow:"0 20px 60px rgba(0,0,0,.4)"}}>
        <div style={{padding:"22px 24px 14px",borderBottom:"1px solid #f1f5f9",position:"sticky",top:0,background:"#fff"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:12}}>
            <div>
              <div style={{fontWeight:900,fontSize:18,color:"#0f172a"}}>🔔 Benachrichtigungen einrichten</div>
              <p style={{fontSize:13,color:"#64748b",margin:"4px 0 0",lineHeight:1.5}}>
                Du verpasst keinen Termin mehr — und Eltern werden 3 Tage vorher erinnert, wenn sie noch nicht abgestimmt haben.
              </p>
            </div>
            <button onClick={onClose} style={{background:"none",border:"none",fontSize:22,color:"#64748b",cursor:"pointer",padding:"0 4px",fontFamily:"inherit"}}>×</button>
          </div>
          <div style={{display:"flex",gap:5,marginTop:14}}>
            {tabs.map(tt=>(
              <button key={tt.id} onClick={()=>setTab(tt.id)}
                style={{flex:1,padding:"9px 8px",borderRadius:11,border:"none",
                  background:tab===tt.id?"#16a34a":"#f1f5f9",
                  color:tab===tt.id?"#fff":"#475569",
                  fontWeight:700,fontSize:12.5,cursor:"pointer",fontFamily:"inherit"}}>
                <span style={{marginRight:5}}>{tt.icon}</span>{tt.label}
              </button>
            ))}
          </div>
        </div>
        <div style={{padding:"18px 24px 22px"}}>
          {steps[tab].map((step,i)=>(
            <div key={i} style={{display:"flex",gap:12,marginBottom:14,paddingBottom:14,borderBottom:i<steps[tab].length-1?"1px solid #f1f5f9":"none"}}>
              <div style={{width:28,height:28,borderRadius:9,background:"#16a34a",color:"#fff",
                display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:13,flexShrink:0}}>{i+1}</div>
              <div style={{flex:1}}>
                <div style={{fontWeight:800,fontSize:14,color:"#0f172a"}}>{step.t}</div>
                <div style={{fontSize:13,color:"#64748b",lineHeight:1.55,marginTop:3}}>{step.s}</div>
              </div>
            </div>
          ))}
          <div style={{background:"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:12,padding:"12px 14px",marginTop:6,fontSize:12.5,color:"#15803d",lineHeight:1.55}}>
            <b>Wichtig:</b> Damit der Verein Benachrichtigungen senden kann, muss der Vereins-Admin die Push-Funktion einmalig in den Settings aktiviert haben (Schlüssel + Edge-Function).
          </div>
        </div>
      </div>
    </div>
  );
}

const CONTACT_TEMPLATES = [
  { id:"freundschaft", label:"Freundschaftsspiel anfragen", icon:"⚽",
    msg: ({club})=>`Hallo,\n\nwir würden gerne ein Freundschaftsspiel gegen euch organisieren.\n\nVorschlag:\n• Datum: \n• Uhrzeit: \n• Heim/Auswärts: \n• Altersklasse: \n\nWürde euch das passen? Antwort gerne per Mail oder Telefon.\n\nViele Grüße`
  },
  { id:"turnier", label:"Zum Turnier einladen", icon:"🏆",
    msg: ({club})=>`Hallo,\n\nwir veranstalten ein Turnier und würden euch gerne dazu einladen.\n\nEckdaten:\n• Datum: \n• Ort: \n• Altersklassen: \n• Startgebühr: \n• Anmeldeschluss: \n\nMeldet euch bei Interesse - genauere Infos und Anmeldeunterlagen schicke ich euch dann zu.\n\nViele Grüße`
  },
  { id:"training", label:"Gemeinsames Training", icon:"👟",
    msg: ({club})=>`Hallo,\n\nwir wollten anfragen, ob ihr Interesse an einem gemeinsamen Training mit uns hättet (eine oder mehrere Einheiten).\n\nVorschlag:\n• Wann: \n• Wo: \n• Altersklasse / Mannschaft: \n• Schwerpunkt (z. B. Spielform, Technik): \n\nIst das aus eurer Sicht machbar?\n\nViele Grüße`
  },
  { id:"hospitation", label:"Hospitation Trainer", icon:"🎯",
    msg: ({club})=>`Hallo,\n\nich/wir würden gerne bei einem eurer Trainings hospitieren und mir/uns ein paar Impulse holen.\n\n• Wunsch-Datum: \n• Wer kommt vorbei: \n• Interesse besonders an: \n\nGeht das bei euch?\n\nViele Grüße`
  },
];

function ContactForm({ cl, onSend, onClose }) {
  const [f,setF]=useState({name:"",email:"",msg:""});
  const [sent,setSent]=useState(false);
  const [showTpl,setShowTpl]=useState(false);
  const t=TH(cl);
  const send=()=>{if(!f.name.trim()||f.msg.trim().length<5)return;onSend({...f,ts:new Date().toISOString()});setSent(true);};
  const applyTpl = (tpl) => {
    setF(p=>({...p, msg: tpl.msg({club:cl})}));
    setShowTpl(false);
  };
  if(sent) return <div style={{minHeight:"100dvh",background:"#f0fdf4",display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:14,padding:24}}><div style={{fontSize:48}}>✓</div><p style={{fontWeight:800,fontSize:18}}>Anfrage gesendet!</p><button onClick={onClose} style={{padding:"12px 24px",borderRadius:12,border:"none",background:t.p,color:"#fff",fontWeight:800,cursor:"pointer",fontFamily:"inherit"}}>Schließen</button></div>;
  return (
    <div style={{minHeight:"100dvh",background:"#f0f4f8",padding:"24px 20px"}}>
      <style>{CSS}</style><OnlineStatus/>
      <div style={{maxWidth:560,margin:"0 auto"}}>
        <button onClick={onClose} style={{background:"none",border:"none",color:"#64748b",fontWeight:700,fontSize:14,cursor:"pointer",marginBottom:16}}>← Zurück</button>
        <div style={{background:"#fff",borderRadius:18,padding:"22px"}}>
          <div style={{fontWeight:900,fontSize:18,marginBottom:4}}>{cl.name} kontaktieren</div>
          <p style={{fontSize:13,color:"#64748b",margin:"0 0 16px"}}>Nachricht geht an die Admin-Inbox des Vereins. Du kannst eine Vorlage nutzen oder frei schreiben.</p>
          <div style={{display:"flex",flexDirection:"column",gap:10}}>
            <input value={f.name} onChange={e=>setF(p=>({...p,name:e.target.value}))} placeholder="Dein Name (oder Verein)" style={{padding:"11px 14px",fontSize:14,border:"1.5px solid #e2e8f0",borderRadius:11,outline:"none",fontFamily:"inherit"}}/>
            <input value={f.email} onChange={e=>setF(p=>({...p,email:e.target.value}))} placeholder="E-Mail für Antwort (optional, aber empfohlen)" style={{padding:"11px 14px",fontSize:14,border:"1.5px solid #e2e8f0",borderRadius:11,outline:"none",fontFamily:"inherit"}}/>
            <PrivacyNote/>
            <div>
              <button onClick={()=>setShowTpl(s=>!s)} type="button"
                style={{width:"100%",padding:"11px 14px",borderRadius:11,border:`1.5px dashed ${t.p}`,background:"#f8fafc",color:t.p,fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit",marginBottom:showTpl?8:0}}>
                {showTpl?"Vorlagen ausblenden":"📝 Vorlage einfügen…"}
              </button>
              {showTpl && (
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:6,marginBottom:8}}>
                  {CONTACT_TEMPLATES.map(tpl=>(
                    <button key={tpl.id} type="button" onClick={()=>applyTpl(tpl)}
                      style={{padding:"10px 12px",borderRadius:10,border:"1.5px solid #e2e8f0",background:"#fff",color:"#334155",fontWeight:700,fontSize:12.5,cursor:"pointer",fontFamily:"inherit",textAlign:"left",lineHeight:1.4}}>
                      <span style={{marginRight:6}}>{tpl.icon}</span>{tpl.label}
                    </button>
                  ))}
                </div>
              )}
            </div>
            <textarea value={f.msg} onChange={e=>setF(p=>({...p,msg:e.target.value}))} placeholder="Deine Nachricht..." rows={10}
              style={{padding:"12px 14px",fontSize:14,border:"1.5px solid #e2e8f0",borderRadius:11,outline:"none",resize:"vertical",fontFamily:"inherit",lineHeight:1.55}}/>
          </div>
          <button onClick={send} disabled={!f.name.trim()||f.msg.trim().length<5}
            style={{width:"100%",marginTop:14,padding:"13px",borderRadius:12,border:"none",
              background:(f.name.trim()&&f.msg.trim().length>=5)?t.p:"#cbd5e1",
              color:"#fff",fontWeight:800,fontSize:15,
              cursor:(f.name.trim()&&f.msg.trim().length>=5)?"pointer":"not-allowed",fontFamily:"inherit"}}>
            Anfrage senden
          </button>
        </div>
      </div>
    </div>
  );
}

function InboxTab({ data,cid,save,fire,cl }) {
  const t = TH(cl);
  const requests  = (data.contactRequests||[]).filter(r=>r.cid===cid);
  const secLog    = (data.securityLog||[]).filter(s=>s.cid===cid);
  const [view,setView] = useState("inbox"); // inbox | security

  const unreadInbox = requests.filter(r=>!r.read&&!r.blocked).length;
  const unreadSec   = secLog.filter(s=>!s.read).length;

  const markRead = id => save({...data,contactRequests:(data.contactRequests||[]).map(r=>r.id===id?{...r,read:true}:r)});
  const blockSender = (req) => {
    const next = (data.contactRequests||[]).map(r=>
      r.fromEmail===req.fromEmail||r.fromName===req.fromName ? {...r,blocked:true,read:true} : r
    );
    const logEntry = {id:uid(),cid,type:"spam_block",ts:new Date().toISOString(),detail:`Absender "${req.fromName}" blockiert - ${next.filter(r=>r.blocked&&(r.fromEmail===req.fromEmail||r.fromName===req.fromName)).length} Nachrichten`,read:false};
    save({...data,contactRequests:next,securityLog:[...(data.securityLog||[]),logEntry]});
    fire("Absender blockiert und gemeldet");
  };
  const deleteReq = id => save({...data,contactRequests:(data.contactRequests||[]).filter(r=>r.id!==id)});
  const markSecRead = id => save({...data,securityLog:(data.securityLog||[]).map(s=>s.id===id?{...s,read:true}:s)});

  const fmtDate = ts => new Date(ts).toLocaleDateString("de-DE",{day:"2-digit",month:"2-digit",hour:"2-digit",minute:"2-digit"});

  const SEC_TYPES = {
    spam_block:    {icon:"X",col:"#dc2626",bg:"#fee2e2",label:"Spam blockiert"},many_requests: {icon:"!",col:"#d97706",bg:"#fef3c7",label:"Viele Anfragen"},login_fail:    {icon:"?",col:"#7c3aed",bg:"#ede9fe",label:"Fehlerhafte Logins"},suspicious:    {icon:"!!",col:"#dc2626",bg:"#fee2e2",label:"Verdaechtige Aktivität"},};

  const visible = requests.filter(r=>!r.blocked);
  const blocked = requests.filter(r=>r.blocked);

  return (
    <div>
      <PageHead icon="📥" title="Posteingang" sub="Anfragen · Sicherheits-Log"/>
      <div style={{display:"flex",gap:8,marginBottom:16}}>
        {[["inbox",`Posteingang${unreadInbox>0?` (${unreadInbox})`:""}`],["security",`Sicherheit${unreadSec>0?` (${unreadSec})`:""}`]].map(([k,l])=>(
          <button key={k} onClick={()=>setView(k)}
            style={{flex:1,padding:"10px",borderRadius:12,border:`2px solid ${view===k?t.p:"#e2e8f0"}`,background:view===k?t.p:"#fff",color:view===k?"#fff":"#475569",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit",transition:"all .15s"}}>
            {l}
          </button>
        ))}
      </div>

      {}
      {view==="inbox"&&<>
        {visible.some(r=>r.dsgvo)&&(
          <div style={{background:"#ede9fe",border:"1.5px solid #c4b5fd",borderRadius:12,padding:"11px 13px",marginBottom:12,fontSize:12.5,color:"#5b21b6",lineHeight:1.5}}>
            <b>DSGVO-Löschantrag</b> eingegangen. Bitte die betroffenen Daten im Bereich <b>Spieler</b> löschen (erstellt automatisch einen DSGVO-Löschnachweis) und die Anfrage danach als gelesen markieren.
          </div>
        )}
        {visible.length===0&&(
          <div style={{textAlign:"center",padding:"32px",background:"#f8fafc",borderRadius:14,border:"1.5px dashed #e2e8f0"}}>
            <div style={{fontSize:36,marginBottom:8}}>&#x2709;</div>
            <p style={{fontWeight:700,color:"#334155"}}>Keine Anfragen</p>
            <p style={{fontSize:13,color:"#64748b",marginTop:4}}>Wenn jemand euren Verein kontaktiert,erscheint es hier.</p>
          </div>
        )}
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {visible.map(req=>(
            <div key={req.id} style={{background:"#fff",borderRadius:14,border:`1.5px solid ${req.read?"#e2e8f0":"#bfdbfe"}`,overflow:"hidden"}}>
              <div style={{padding:"12px 14px"}}>
                <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
                  <div style={{width:36,height:36,borderRadius:11,background:req.read?"#f1f5f9":"#dbeafe",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800,fontSize:15,color:req.read?"#64748b":"#1d4ed8",flexShrink:0}}>
                    {req.fromName?.[0]?.toUpperCase()||"?"}
                  </div>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:2}}>
                      <span style={{fontWeight:800,fontSize:14,color:"#0f172a"}}>{req.fromName}</span>
                      {req.dsgvo&&<span style={{fontSize:10,fontWeight:800,color:"#7c3aed",background:"#ede9fe",borderRadius:5,padding:"2px 7px"}}>DSGVO-Löschantrag</span>}
                      {!req.read&&<span style={{fontSize:10,fontWeight:800,color:"#1d4ed8",background:"#dbeafe",borderRadius:5,padding:"2px 7px"}}>Neu</span>}
                    </div>
                    {req.fromEmail&&<div style={{fontSize:11,color:"#64748b",marginBottom:4}}>{req.fromEmail}</div>}
                    <p style={{fontSize:13,color:"#334155",lineHeight:1.6,margin:"0 0 6px"}}>{req.msg}</p>
                    <div style={{fontSize:11,color:"#64748b"}}>{fmtDate(req.ts)}</div>
                  </div>
                </div>
              </div>
              <div style={{display:"flex",borderTop:"1px solid #f1f5f9"}}>
                {!req.read&&<button onClick={()=>markRead(req.id)} style={{flex:1,padding:"9px",border:"none",background:"none",color:"#16a34a",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>Gelesen</button>}
                <button onClick={()=>blockSender(req)} style={{flex:1,padding:"9px",border:"none",background:"none",color:"#d97706",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>Blockieren</button>
                <button onClick={()=>deleteReq(req.id)} style={{flex:1,padding:"9px",border:"none",background:"none",color:"#dc2626",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>Löschen</button>
              </div>
            </div>
          ))}
        </div>

        {blocked.length>0&&(
          <div style={{marginTop:16,background:"#fef2f2",borderRadius:12,padding:"12px 14px",border:"1.5px solid #fecaca"}}>
            <div style={{fontWeight:700,fontSize:13,color:"#dc2626",marginBottom:4}}>Blockierte Absender ({blocked.length})</div>
            {[...new Set(blocked.map(r=>r.fromName))].map(name=>(
              <div key={name} style={{fontSize:12,color:"#9f1239",padding:"3px 0"}}>{name} - {blocked.filter(r=>r.fromName===name).length} blockierte Nachricht(en)</div>
            ))}
          </div>
        )}
      </>}

      {}
      {view==="security"&&<>
        <div style={{background:"#eff6ff",borderRadius:13,padding:"12px 14px",border:"1.5px solid #bfdbfe",marginBottom:14,fontSize:13,color:"#1d4ed8",lineHeight:1.6}}>
          Hier siehst du sicherheitsrelevante Ereignisse für deinen Verein. Wir überwachen automatisch ob dein Vereinszugang missbraucht wird.
        </div>
        {secLog.length===0&&(
          <div style={{textAlign:"center",padding:"32px",background:"#f8fafc",borderRadius:14,border:"1.5px dashed #e2e8f0"}}>
            <div style={{fontSize:36,marginBottom:8}}>&#x1F6E1;</div>
            <p style={{fontWeight:700,color:"#16a34a"}}>Alles in Ordnung</p>
            <p style={{fontSize:13,color:"#64748b",marginTop:4}}>Keine ungewoehnlichen Aktivitäten erkannt.</p>
          </div>
        )}
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {secLog.sort((a,b)=>b.ts.localeCompare(a.ts)).map(e=>{
            const st=SEC_TYPES[e.type]||{icon:"i",col:"#64748b",bg:"#f1f5f9",label:e.type};
            return (
              <div key={e.id} style={{background:"#fff",borderRadius:14,border:`1.5px solid ${e.read?"#e2e8f0":st.col+"40"}`,padding:"12px 14px",display:"flex",gap:12,alignItems:"flex-start"}}>
                <div style={{width:36,height:36,borderRadius:11,background:st.bg,display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:13,color:st.col,flexShrink:0}}>{st.icon}</div>
                <div style={{flex:1}}>
                  <div style={{display:"flex",alignItems:"center",gap:7,marginBottom:3}}>
                    <span style={{fontWeight:800,fontSize:13,color:"#0f172a"}}>{st.label}</span>
                    {!e.read&&<span style={{fontSize:10,fontWeight:800,color:st.col,background:st.bg,borderRadius:5,padding:"2px 7px"}}>Neu</span>}
                  </div>
                  <p style={{fontSize:12,color:"#64748b",margin:"0 0 4px",lineHeight:1.5}}>{e.detail}</p>
                  <div style={{fontSize:11,color:"#64748b"}}>{fmtDate(e.ts)}</div>
                </div>
                {!e.read&&<button onClick={()=>markSecRead(e.id)} style={{width:28,height:28,borderRadius:8,background:"#f1f5f9",border:"none",color:"#64748b",cursor:"pointer",fontSize:12,flexShrink:0}}>ok</button>}
              </div>
            );
          })}
        </div>
        <div style={{marginTop:14,background:"#f8fafc",borderRadius:12,padding:"12px 14px",border:"1.5px solid #e2e8f0",fontSize:12,color:"#64748b",lineHeight:1.6}}>
          Automatischer Schutz aktiv: Absender die mehr als 5 Nachrichten senden werden automatisch blockiert und gemeldet. Dein Admin-Zugang wird bei 10 Fehlversuchen temporaer gesperrt.
        </div>
      </>}
    </div>
  );
}

// Öffentliches Warteliste-Formular: Interessent:innen tragen sich mit Kontakt ein.
// Kontakt sehen später NUR Trainer/Verein.
function WaitlistForm({ cl, teams=[], preTid=null, preCat=null, onSubmit, onClose }) {
  const t=TH(cl);
  const { tr } = useT();
  const cats=[...new Set((teams||[]).map(tm=>tm.cat||tm.name))];
  const [f,setF]=useState({ childName:"", by:"", gender:"m", parentName:"", contact:"", note:"", cat:preCat||cats[0]||"", tid:preTid||"" });
  const [sent,setSent]=useState(false);
  const valid=f.childName.trim().length>1 && f.parentName.trim().length>1 && f.contact.trim().length>=5;
  const inp={width:"100%",padding:"11px 13px",fontSize:14,border:"1.5px solid #e2e8f0",borderRadius:11,outline:"none",fontFamily:"inherit",boxSizing:"border-box"};
  const submit=()=>{ if(!valid) return; onSubmit({ ...f, by: parseInt(f.by)||null, childName:f.childName.trim(), parentName:f.parentName.trim(), contact:f.contact.trim(), note:f.note.trim() }); setSent(true); };
  return (
    <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(0,0,0,.6)",zIndex:2100,display:"flex",alignItems:"flex-end",justifyContent:"center",backdropFilter:"blur(6px)"}}>
      <div onClick={e=>e.stopPropagation()} style={{background:"#fff",borderRadius:"22px 22px 0 0",width:"100%",maxWidth:520,maxHeight:"92dvh",overflowY:"auto",padding:"18px 20px calc(28px + env(safe-area-inset-bottom))",fontFamily:"inherit"}}>
        <div style={{display:"flex",justifyContent:"center",marginBottom:12}}><div style={{width:44,height:4,borderRadius:99,background:"#e2e8f0"}}/></div>
        {sent ? (
          <div style={{textAlign:"center",padding:"18px 8px 8px"}}>
            <div style={{fontSize:44,marginBottom:8}}>✅</div>
            <div style={{fontWeight:900,fontSize:18,color:"#0f172a",marginBottom:6}}>{tr("wfDoneT")}</div>
            <p style={{fontSize:13.5,color:"#64748b",lineHeight:1.55,marginBottom:16}}>{tr("wfDoneSub")}</p>
            <button onClick={onClose} style={{width:"100%",padding:"13px",borderRadius:13,border:"none",background:t.p,color:contrast(t.p),fontWeight:800,fontSize:15,cursor:"pointer",fontFamily:"inherit"}}>{tr("wfClose")}</button>
          </div>
        ) : (<>
          <div style={{fontWeight:900,fontSize:18,color:"#0f172a",marginBottom:4}}>{tr("wfTitle")}</div>
          <p style={{fontSize:12.5,color:"#64748b",lineHeight:1.5,marginBottom:14}}>{tr("wfIntro")}</p>
          <div style={{display:"flex",flexDirection:"column",gap:9}}>
            <input value={f.childName} onChange={e=>setF(p=>({...p,childName:e.target.value}))} placeholder={tr("wfChild")} style={inp}/>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:9}}>
              <input value={f.by} onChange={e=>setF(p=>({...p,by:e.target.value}))} inputMode="numeric" placeholder={tr("wfYear")} style={inp}/>
              <select value={f.gender} onChange={e=>setF(p=>({...p,gender:e.target.value}))} style={inp}>
                <option value="m">{tr("wfBoy")}</option><option value="w">{tr("wfGirl")}</option>
              </select>
            </div>
            {cats.length>0&&(
              <select value={f.cat} onChange={e=>setF(p=>({...p,cat:e.target.value}))} style={inp}>
                <option value="">{tr("wfWishCat")}</option>
                {cats.map(c=><option key={c} value={c}>{c}</option>)}
              </select>
            )}
            <input value={f.parentName} onChange={e=>setF(p=>({...p,parentName:e.target.value}))} placeholder={tr("wfParent")} style={inp}/>
            <input value={f.contact} onChange={e=>setF(p=>({...p,contact:e.target.value}))} placeholder={tr("wfContact")} style={inp}/>
            <textarea value={f.note} onChange={e=>setF(p=>({...p,note:e.target.value}))} rows={2} placeholder={tr("wfMsg")} style={{...inp,resize:"vertical"}}/>
            <div style={{fontSize:11,color:"#64748b",lineHeight:1.45}}>{tr("wfPrivacy")}</div>
          </div>
          <div style={{display:"flex",gap:9,marginTop:14}}>
            <button onClick={onClose} style={{flex:1,padding:"12px",borderRadius:12,border:"1.5px solid #e2e8f0",background:"#fff",color:"#475569",fontWeight:700,fontSize:14,cursor:"pointer",fontFamily:"inherit"}}>{tr("wfCancel")}</button>
            <button onClick={submit} disabled={!valid} style={{flex:2,padding:"12px",borderRadius:12,border:"none",background:valid?t.p:"#e2e8f0",color:valid?contrast(t.p):"#94a3b8",fontWeight:800,fontSize:14,cursor:valid?"pointer":"default",fontFamily:"inherit"}}>{tr("wfSubmit")}</button>
          </div>
        </>)}
      </div>
    </div>
  );
}

// Trainer/Admin-Ansicht der Warteliste (mit Kontakt). Trainer sehen die Jugenden
// ihrer Mannschaften, Admin alle.
const WAITLIST_STATUS = { open:{l:"offen",c:"#b45309",bg:"#fef3c7"}, contacted:{l:"kontaktiert",c:"#1d4ed8",bg:"#dbeafe"}, admitted:{l:"aufgenommen",c:"#15803d",bg:"#dcfce7"}, declined:{l:"abgelehnt",c:"#64748b",bg:"#f1f5f9"} };
function WaitlistTab({ data, cid, myTids, session, save, fire, cl, isAdmin=false }) {
  const t=TH(cl);
  const teams=(data.teams||[]).filter(tm=>tm.cid===cid);
  const myCats=new Set(teams.filter(tm=>isAdmin||myTids.includes(tm.id)).map(tm=>tm.cat||tm.name));
  const visible=(data.waitlist||[]).filter(w=>w.cid===cid && (isAdmin || !w.cat || myCats.has(w.cat) || (w.tid&&myTids.includes(w.tid))))
    .sort((a,b)=>String(b.ts||"").localeCompare(String(a.ts||"")));
  const openN=visible.filter(w=>(w.status||"open")==="open").length;
  const setStatus=(id,status)=>save({...data, waitlist:(data.waitlist||[]).map(w=>w.id===id?{...w,status}:w)});
  const del=(id)=>{ if(typeof window!=="undefined"&&window.confirm&&!window.confirm("Eintrag von der Warteliste entfernen?"))return; save({...data, waitlist:(data.waitlist||[]).filter(w=>w.id!==id)}); fire&&fire("Von der Warteliste entfernt"); };
  const admit=(w)=>{
    const tid=w.tid||teams.find(tm=>(tm.cat||tm.name)===w.cat)?.id||"";
    if(typeof window!=="undefined"&&window.confirm&&!window.confirm(`„${w.childName}" als Spieler in den Kader übernehmen?`))return;
    const prof={...mkPlayer({name:w.childName||w.parentName||"Neuer Spieler", by:w.by||2018, gender:w.gender||"m", mainTid:tid}), cid, seasonId:activeSid(data,cid)||"", notes:[w.parentName?`Eltern: ${w.parentName}`:"", w.contact?`Kontakt: ${w.contact}`:"", w.note||""].filter(Boolean).join(" · ")};
    save({...data, playerProfiles:[...(data.playerProfiles||[]), prof], waitlist:(data.waitlist||[]).map(x=>x.id===w.id?{...x,status:"admitted"}:x)});
    fire&&fire("Als Spieler in den Kader übernommen");
  };
  const contactHref=(c)=>{ const v=String(c||"").trim(); if(/@/.test(v)) return "mailto:"+v; const tel=v.replace(/[^\d+]/g,""); return tel.length>=5?"tel:"+tel:null; };
  return (
    <div>
      <PageHead icon="📋" title="Warteliste" sub={`${visible.length} Einträge${openN>0?` · ${openN} offen`:""} · Kontakt nur für Trainer/Verein`}/>
      {visible.length===0&&<EmptyBox icon="📭" title="Noch niemand auf der Warteliste" sub={'Interessierte können sich beim Team-Login über „Auf die Warteliste“ eintragen – v. a. wenn ein Team voll ist.'}/>}
      <div style={{display:"flex",flexDirection:"column",gap:9}}>
        {visible.map(w=>{ const st=WAITLIST_STATUS[w.status||"open"]||WAITLIST_STATUS.open; const href=contactHref(w.contact); return (
          <div key={w.id} style={{background:"#fff",border:"1.5px solid #e2e8f0",borderRadius:14,padding:"12px 14px"}}>
            <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
              <Av name={w.childName||"?"} sz={38}/>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:800,fontSize:14.5,color:"#0f172a",display:"flex",alignItems:"center",gap:7,flexWrap:"wrap"}}>{w.childName}
                  <span style={{fontSize:10.5,fontWeight:800,color:st.c,background:st.bg,borderRadius:6,padding:"1px 7px"}}>{st.l}</span>
                </div>
                <div style={{fontSize:12,color:"#64748b",marginTop:2}}>{w.by?`Jg. ${w.by}`:""}{w.gender?` · ${w.gender==="w"?"Mädchen":"Junge"}`:""}{w.cat?` · ${w.cat}`:""}{w.ts?` · ${fmtD(String(w.ts).slice(0,10))}`:""}</div>
                <div style={{fontSize:12.5,color:"#334155",marginTop:6,lineHeight:1.5}}>
                  <div>👤 {w.parentName||"—"}</div>
                  <div>📞 {href?<a href={href} style={{color:t.p,fontWeight:700,textDecoration:"none"}}>{w.contact}</a>:w.contact}</div>
                  {w.note&&<div style={{color:"#64748b",marginTop:2}}>💬 {w.note}</div>}
                </div>
              </div>
            </div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap",marginTop:10,paddingTop:10,borderTop:"1px solid #f1f5f9"}}>
              {(w.status||"open")!=="contacted"&&<button onClick={()=>setStatus(w.id,"contacted")} style={{flex:"1 1 auto",padding:"8px 10px",borderRadius:9,border:"1.5px solid #bfdbfe",background:"#eff6ff",color:"#1d4ed8",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>kontaktiert</button>}
              <button onClick={()=>admit(w)} style={{flex:"1 1 auto",padding:"8px 10px",borderRadius:9,border:"none",background:"#16a34a",color:"#fff",fontWeight:800,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>In Kader übernehmen</button>
              {(w.status||"open")!=="declined"&&<button onClick={()=>setStatus(w.id,"declined")} style={{flex:"1 1 auto",padding:"8px 10px",borderRadius:9,border:"1.5px solid #e2e8f0",background:"#fff",color:"#64748b",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>ablehnen</button>}
              <button onClick={()=>del(w.id)} title="Löschen" style={{padding:"8px 11px",borderRadius:9,border:"none",background:"#fee2e2",color:"#dc2626",fontWeight:800,fontSize:12,cursor:"pointer",fontFamily:"inherit"}}>🗑</button>
            </div>
          </div>
        );})}
      </div>
    </div>
  );
}


/*  ONBOARDING WIZARD (Admin - erster Login)  */
function OnboardingWizard({ cl, data, save, fire, onDone }) {
  const t = TH(cl);
  const [step, setStep] = useState(1);
  const [legalAck, setLegalAck] = useState(false);
  const STEPS = 5;
  const SPORT_CATS = {
    fussball: [
      {id:"bambinis",label:"Bambinis",years:"U6"},
      {id:"g_jug",label:"G-Jugend",years:"U7"},
      {id:"f_jug",label:"F-Jugend",years:"U8-U9"},
      {id:"e_jug",label:"E-Jugend",years:"U10-U11"},
      {id:"d_jug",label:"D-Jugend",years:"U12-U13"},
      {id:"c_jug",label:"C-Jugend",years:"U14-U15"},
      {id:"b_jug",label:"B-Jugend",years:"U16-U17"},
      {id:"a_jug",label:"A-Jugend",years:"U18-U19"},
      {id:"senioren",label:"1. Senioren",years:"Aktive"},
      {id:"senioren2",label:"2. Senioren",years:"Aktive"},
      {id:"senioren3",label:"3. Senioren",years:"Aktive"},
      {id:"altherren",label:"Alt-Herren",years:"Ue32"},
      {id:"frauen",label:"Frauen",years:"Aktive"},
      {id:"maedchen",label:"Maedchen",years:"Jugend"},
    ],
    handball: [
      {id:"minis",label:"Mini-Handball",years:"U6-U8"},
      {id:"e_jug",label:"E-Jugend",years:"U10"},
      {id:"d_jug",label:"D-Jugend",years:"U12"},
      {id:"c_jug",label:"C-Jugend",years:"U14"},
      {id:"b_jug",label:"B-Jugend",years:"U16"},
      {id:"a_jug",label:"A-Jugend",years:"U18"},
      {id:"senioren",label:"Senioren",years:"Aktive"},
      {id:"frauen",label:"Frauen",years:"Aktive"},
    ],
    tennis: [
      {id:"kinder",label:"Kinder",years:"U10"},
      {id:"jugend",label:"Jugend",years:"U18"},
      {id:"erwachsene",label:"Erwachsene",years:"Aktive"},
      {id:"senioren",label:"Senioren",years:"Ue60"},
    ],
    default: [
      {id:"jugend",label:"Jugend",years:""},
      {id:"erwachsene",label:"Erwachsene",years:""},
      {id:"senioren",label:"Senioren",years:""},
    ]
  };
  const cats = SPORT_CATS[cl.sport||"fussball"] || SPORT_CATS.default;
  const TEAM_COLORS = ["#16a34a","#2563eb","#d97706","#7c3aed","#dc2626","#0891b2","#059669","#ea580c"];

  const [selCats, setSelCats] = useState([]);
  const [teamCounts, setTeamCounts] = useState({});
  const [trainerName, setTrainerName] = useState("");
  const [trainerPw, setTrainerPw] = useState("");
  const [fieldName, setFieldName] = useState("Hauptplatz");
  const [fieldSurface, setFieldSurface] = useState("Rasen");
  const [fieldSplit, setFieldSplit] = useState(1);
  const SURFACE_TPL = {Rasen:"rasen",Kunstrasen:"kunstrasen",Halle:"halle",Sand:"mehrzweck",Asche:"asche"};

  const toggleCat = id => {
    const n = selCats.includes(id) ? selCats.filter(x=>x!==id) : [...selCats,id];
    setSelCats(n);
    if(!teamCounts[id]) setTeamCounts(prev=>({...prev,[id]:1}));
  };

  const finish = () => {
    const newTeams = selCats.flatMap((catId,ci) => {
      const cat = cats.find(x=>x.id===catId);
      const cnt = teamCounts[catId]||1;
      return Array.from({length:cnt},(_,i)=>({
        id: uid(), cid: cl.id,
        name: cnt===1 ? cat.label : cat.label+" "+(i+1),
        icon: cat.label.slice(0,2).toUpperCase(),
        col: TEAM_COLORS[(ci*cnt+i) % TEAM_COLORS.length],
        pub: true, pwd: catId.slice(0,2)+(i+1),
        cat: cat.label, years: cat.years
      }));
    });
    // Kein Passwort eingegeben? Dann automatisch einen kurzen Login-Code
    // erzeugen und dem Admin anzeigen - sonst gibt es einen Trainer, dessen
    // Passwort niemand kennt ("trainer" wurde frueher still gesetzt).
    const genCode = (trainerName.trim() && !trainerPw.trim())
      ? Math.random().toString(36).slice(2,6).toUpperCase()
      : null;
    const trainerPlainPw = trainerPw.trim() || genCode;
    const newTrainers = trainerName.trim() ? [{
      id: uid(), cid: cl.id, name: trainerName.trim(),
      role: "Trainer", tids: newTeams.slice(0,1).map(x=>x.id),
      pw: hashPw(trainerPlainPw), phone: "", email: ""
    }] : [];
    const newFields = fieldName.trim() ? [{
      id: uid(), cid: cl.id, name: fieldName.trim(),
      template: SURFACE_TPL[fieldSurface]||"rasen",
      split: fieldSplit||1, weather: "any",
      surface: fieldSurface, segments: fieldSplit||1
    }] : [];
    const updClubs = (data.clubs||[]).map(x=>x.id===cl.id?{...x,onboarded:true}:x);
    save({
      ...data, clubs: updClubs,
      teams: [...(data.teams||[]),...newTeams],
      trainers: [...(data.trainers||[]),...newTrainers],
      fields: [...(data.fields||[]),...newFields],
    });
    if (genCode) {
      window.alert(`Login-Code für Trainer "${trainerName.trim()}":\n\n${genCode}\n\nBitte notieren und an den Trainer weitergeben. Du kannst ihn jederzeit im Trainer-Tab ändern.`);
    }
    fire("Verein eingerichtet - Los geht es!");
    onDone();
  };

  const ok = () => {
    if(step===2) return selCats.length>0;
    return true;
  };

  const pct = Math.round((step/STEPS)*100);

  return (
    <div style={{position:"fixed",inset:0,background:"linear-gradient(160deg,#0f172a,#052e16 60%)",zIndex:980,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:"20px"}}>
      <style>{`@keyframes down{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:none}}`}</style>
      <div style={{width:"100%",maxWidth:480,background:"#fff",borderRadius:24,overflow:"hidden",animation:"down .3s ease",maxHeight:"90dvh",display:"flex",flexDirection:"column"}}>
        {/* Header */}
        <div style={{background:`linear-gradient(135deg,${t.s||"#052e16"},${t.p})`,padding:"20px 22px 16px",flexShrink:0}}>
          <div style={{color:"rgba(255,255,255,.6)",fontSize:11,fontWeight:700,marginBottom:4}}>
            SCHRITT {step} VON {STEPS}
          </div>
          <div style={{color:"#fff",fontWeight:900,fontSize:20,marginBottom:12}}>
            {["","Willkommen!","Abteilungen","Teams","Trainer","Spielfeld"][step]}
          </div>
          <div style={{height:5,background:"rgba(255,255,255,.2)",borderRadius:99}}>
            <div style={{height:"100%",background:"rgba(255,255,255,.9)",borderRadius:99,width:pct+"%",transition:"width .4s"}}/>
          </div>
        </div>

        {/* Content */}
        <div style={{flex:1,overflowY:"auto",padding:"20px 22px 8px"}}>

          {step===1&&(
            <div>
              <div style={{textAlign:"center",marginBottom:20}}>
                <div style={{width:72,height:72,borderRadius:20,background:t.p+"18",display:"flex",alignItems:"center",justifyContent:"center",fontSize:36,margin:"0 auto 12px"}}>{cl.em||"D"}</div>
                <h2 style={{fontWeight:900,fontSize:22,color:"#0f172a"}}>{cl.name}</h2>
                <p style={{color:"#64748b",fontSize:14,marginTop:6,lineHeight:1.6}}>
                  Richte deinen Verein in wenigen Schritten ein.
                  Das dauert ca. 3 Minuten.
                </p>
              </div>
              <div style={{background:"#f0fdf4",borderRadius:14,padding:"14px 16px",border:"1.5px solid #bbf7d0"}}>
                <div style={{fontWeight:700,fontSize:13,color:"#166534",marginBottom:8}}>Was wir einrichten:</div>
                {["Abteilungen und Teams","Ersten Trainer anlegen","Spielfeld konfigurieren"].map((item,i)=>(
                  <div key={i} style={{display:"flex",alignItems:"center",gap:10,marginBottom:6}}>
                    <div style={{width:20,height:20,borderRadius:"50%",background:"#16a34a",display:"flex",alignItems:"center",justifyContent:"center",color:"#fff",fontSize:11,fontWeight:800,flexShrink:0}}>{i+1}</div>
                    <span style={{fontSize:13,color:"#334155"}}>{item}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {step===2&&(
            <div>
              <p style={{color:"#64748b",fontSize:13,marginBottom:14,lineHeight:1.5}}>
                Welche Abteilungen gibt es in deinem Verein? Du kannst später weitere hinzufügen.
              </p>
              <div style={{display:"flex",flexDirection:"column",gap:7}}>
                {cats.map(cat=>{
                  const sel = selCats.includes(cat.id);
                  return (
                    <div key={cat.id} onClick={()=>toggleCat(cat.id)}
                      style={{display:"flex",alignItems:"center",gap:12,padding:"11px 14px",borderRadius:13,border:`2px solid ${sel?t.p:"#e2e8f0"}`,background:sel?t.p+"10":"#fff",cursor:"pointer",transition:"all .15s"}}>
                      <div style={{width:32,height:32,borderRadius:9,background:sel?t.p:"#f1f5f9",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:12,color:sel?"#fff":"#64748b",flexShrink:0}}>
                        {cat.label.slice(0,2).toUpperCase()}
                      </div>
                      <div style={{flex:1}}>
                        <div style={{fontWeight:700,fontSize:14,color:sel?t.p:"#334155"}}>{cat.label}</div>
                        {cat.years&&<div style={{fontSize:11,color:"#64748b"}}>{cat.years}</div>}
                      </div>
                      <div style={{width:20,height:20,borderRadius:"50%",border:`${sel?"6px":"2px"} solid ${sel?t.p:"#cbd5e1"}`,transition:"all .2s",flexShrink:0}}/>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {step===3&&(
            <div>
              <p style={{color:"#64748b",fontSize:13,marginBottom:14,lineHeight:1.5}}>
                Wie viele Mannschaften gibt es pro Abteilung?
              </p>
              {selCats.map(catId=>{
                const cat = cats.find(x=>x.id===catId);
                const cnt = teamCounts[catId]||1;
                return (
                  <div key={catId} style={{background:"#fff",borderRadius:13,padding:"13px 16px",border:"1.5px solid #e2e8f0",marginBottom:10}}>
                    <div style={{fontWeight:700,fontSize:14,color:"#0f172a",marginBottom:8}}>{cat.label}</div>
                    <div style={{display:"flex",alignItems:"center",gap:12}}>
                      <button onClick={()=>setTeamCounts(p=>({...p,[catId]:Math.max(1,cnt-1)}))}
                        style={{width:36,height:36,borderRadius:10,border:"1.5px solid #e2e8f0",background:"#f8fafc",cursor:"pointer",fontSize:18,fontWeight:800,color:"#64748b"}}>-</button>
                      <div style={{flex:1,textAlign:"center"}}>
                        <div style={{fontWeight:900,fontSize:26,color:t.p,lineHeight:1}}>{cnt}</div>
                        <div style={{fontSize:11,color:"#64748b",marginTop:2}}>
                          {cnt===1 ? cat.label+" 1" : Array.from({length:cnt},(_,i)=>cat.label+" "+(i+1)).join(", ")}
                        </div>
                      </div>
                      <button onClick={()=>setTeamCounts(p=>({...p,[catId]:Math.min(9,cnt+1)}))}
                        style={{width:36,height:36,borderRadius:10,border:"1.5px solid #e2e8f0",background:"#f8fafc",cursor:"pointer",fontSize:18,fontWeight:800,color:"#64748b"}}>+</button>
                    </div>
                  </div>
                );
              })}
              <div style={{background:"#eff6ff",borderRadius:12,padding:"11px 14px",fontSize:12,color:"#1d4ed8",lineHeight:1.5}}>
                Jede Mannschaft bekommt automatisch einen Eltern-Zugangscode.
                Du kannst ihn später anpassen.
              </div>
            </div>
          )}

          {step===4&&(
            <div>
              <p style={{color:"#64748b",fontSize:13,marginBottom:14,lineHeight:1.5}}>
                Wer ist der erste Trainer? (Optional - du kannst das später machen)
              </p>
              <div style={{display:"flex",flexDirection:"column",gap:10}}>
                <input value={trainerName} onChange={e=>setTrainerName(e.target.value)}
                  placeholder="Name (z.B. Max M.)"
                  style={{padding:"12px 14px",fontSize:14,border:`1.5px solid ${trainerName?"#16a34a":"#e2e8f0"}`,borderRadius:12,outline:"none"}}/>
                <div style={{fontSize:12,color:"#64748b",marginTop:-4}}>Datenschutz: Bitte nur Vorname, höchstens Nachname-Initial.</div>
                <PwInput value={trainerPw} onChange={e=>setTrainerPw(e.target.value)}
                  placeholder="Passwort für den Trainer"
                  style={{padding:"12px 14px",fontSize:14,border:"1.5px solid #e2e8f0",borderRadius:12,outline:"none"}}/>
                {trainerName&&!trainerPw&&<div style={{fontSize:12,color:"#0891b2",background:"#e0f2fe",borderRadius:9,padding:"8px 12px"}}>
                  Leer lassen ist ok - dann wird automatisch ein Login-Code erzeugt und dir angezeigt.
                </div>}
              </div>
              <button onClick={()=>{ setTrainerName(""); setTrainerPw(""); setStep(5); }}
                style={{marginTop:12,background:"none",border:"none",color:"#64748b",fontSize:13,cursor:"pointer",textDecoration:"underline"}}>
                Überspringen - später hinzufügen
              </button>
            </div>
          )}

          {step===5&&(
            <div>
              <p style={{color:"#64748b",fontSize:13,marginBottom:14,lineHeight:1.5}}>
                Habt ihr einen Sportplatz oder eine Halle? (Optional)
              </p>
              <div style={{display:"flex",flexDirection:"column",gap:10}}>
                <input value={fieldName} onChange={e=>setFieldName(e.target.value)}
                  placeholder="z.B. Hauptplatz, Sporthalle"
                  style={{padding:"12px 14px",fontSize:14,border:`1.5px solid ${fieldName?"#16a34a":"#e2e8f0"}`,borderRadius:12,outline:"none"}}/>
                <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                  {["Rasen","Kunstrasen","Halle","Sand","Asche"].map(s=>(
                    <button key={s} onClick={()=>setFieldSurface(s)}
                      style={{padding:"8px 14px",borderRadius:10,border:`2px solid ${fieldSurface===s?t.p:"#e2e8f0"}`,background:fieldSurface===s?t.p:"#fff",color:fieldSurface===s?"#fff":"#334155",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>
                      {s}
                    </button>
                  ))}
                </div>
                <div style={{fontSize:11,fontWeight:800,color:"#64748b",letterSpacing:.4,marginTop:6}}>FELDGRÖSSE / AUFTEILUNG</div>
                <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                  {SPLIT_OPTIONS.map(o=>(
                    <button key={o.id} onClick={()=>setFieldSplit(o.id)}
                      style={{padding:"8px 12px",borderRadius:10,border:`2px solid ${fieldSplit===o.id?t.p:"#e2e8f0"}`,background:fieldSplit===o.id?t.p:"#fff",color:fieldSplit===o.id?"#fff":"#334155",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>
                      {o.label}
                    </button>
                  ))}
                </div>
                <div style={{fontSize:11,color:"#64748b",lineHeight:1.5}}>Wie viele Teams können gleichzeitig spielen? Kannst du später unter „Platz" jederzeit ändern oder weitere Plätze anlegen.</div>
              </div>
              <div style={{background:"#f0fdf4",borderRadius:12,padding:"12px 14px",border:"1.5px solid #bbf7d0",marginTop:16,fontSize:12,color:"#166534",lineHeight:1.6}}>
                Zusammenfassung:<br/>
                {selCats.length} Abteilungen, {selCats.reduce((s,id)=>s+(teamCounts[id]||1),0)} Teams
                {trainerName&&`, Trainer: ${trainerName}`}
                {fieldName&&`, Platz: ${fieldName}`}
              </div>
            </div>
          )}
        </div>

        {step===STEPS&&(
          <label style={{display:"flex",gap:10,alignItems:"flex-start",margin:"0 22px 4px",background:"#fffbeb",border:"1.5px solid #fde68a",borderRadius:12,padding:"11px 13px",cursor:"pointer"}}>
            <input type="checkbox" checked={legalAck} onChange={e=>setLegalAck(e.target.checked)} style={{marginTop:2}}/>
            <span style={{fontSize:12,color:"#92400e",lineHeight:1.5}}>🔒 Mir ist bewusst: Bevor Daten Minderjähriger verarbeitet werden, müssen <b>Impressum</b> und <b>Datenschutzerklärung</b> hinterlegt sein (später unter Einstellungen → Datenschutz) und die <b>Eltern-Einwilligung</b> (Art. 8 DSGVO) eingeholt werden.</span>
          </label>
        )}

        {/* Navigation */}
        <div style={{padding:"12px 22px 32px",borderTop:"1px solid #f1f5f9",display:"flex",gap:10,flexShrink:0}}>
          {step>1
            ? <button onClick={()=>setStep(s=>s-1)} style={{flex:1,padding:"13px",borderRadius:13,border:"1.5px solid #e2e8f0",background:"#fff",color:"#475569",fontWeight:700,fontSize:14,cursor:"pointer",fontFamily:"inherit"}}>Zurück</button>
            : <div style={{flex:1}}/>
          }
          {step<STEPS
            ? <button onClick={()=>ok()&&setStep(s=>s+1)} disabled={!ok()}
                style={{flex:2,padding:"13px",borderRadius:13,border:"none",background:ok()?t.p:"#e2e8f0",color:ok()?"#fff":"#64748b",fontWeight:800,fontSize:15,cursor:ok()?"pointer":"default",fontFamily:"inherit",transition:"all .2s"}}>
                Weiter
              </button>
            : <button onClick={()=>legalAck&&finish()} disabled={!legalAck}
                style={{flex:2,padding:"13px",borderRadius:13,border:"none",background:legalAck?t.p:"#e2e8f0",color:legalAck?"#fff":"#64748b",fontWeight:800,fontSize:15,cursor:legalAck?"pointer":"default",fontFamily:"inherit",boxShadow:legalAck?`0 4px 20px ${t.p}44`:"none"}}>
                Verein einrichten!
              </button>
          }
        </div>
      </div>
    </div>
  );
}

import { LegalPage } from "./legal.jsx";

import { AFFILIATE_IDS, applyAffiliateIds, AFFILIATES, ADSENSE_CONFIG } from "./affiliates.js";

function pickAffiliate(trigger) {
  const list = AFFILIATES.filter(a=>a.trigger===trigger);
  if (!list.length) return null;
  // Sortierung: konfigurierte IDs zuerst, dann nach weight
  list.sort((a,b)=>{
    const aOk = a.idKey ? !!AFFILIATE_IDS[a.idKey] : 1;
    const bOk = b.idKey ? !!AFFILIATE_IDS[b.idKey] : 1;
    if (aOk !== bOk) return bOk - aOk;
    return (b.weight||0) - (a.weight||0);
  });
  return list[0];
}
function affiliateUrl(aff) {
  if (!aff) return "#";
  const id = aff.idKey ? AFFILIATE_IDS[aff.idKey] : "";
  try { return aff.url(id); } catch { return "#"; }
}

function AffiliateBanner({ trigger, style={}, slim=false }) {
  const { tr } = useT();
  const [dismissed, setDismissed] = useState(false);
  const aff = pickAffiliate(trigger);
  if (!aff || dismissed) return null;
  const onClick = () => {
    try { trackEventGeo&&trackEventGeo("affiliate_click", aff.id); } catch {}
    window.open(affiliateUrl(aff), "_blank", "noopener,noreferrer");
  };
  if (slim) return (
    <div style={{display:"flex",alignItems:"center",gap:8,background:"#f8fafc",border:"1px solid #eef2f7",borderRadius:10,padding:"7px 11px",...style}}>
      <span style={{fontSize:8.5,fontWeight:800,color:"#64748b",letterSpacing:.5,flexShrink:0}}>{tr("adLabel")}</span>
      <span onClick={onClick} style={{flex:1,minWidth:0,fontSize:12,fontWeight:600,color:"#475569",cursor:"pointer",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{aff.text} <span style={{color:"#64748b"}}>· {tr("adMark")}</span></span>
      <button onClick={()=>setDismissed(true)} aria-label="Werbung ausblenden" style={{width:20,height:20,borderRadius:5,background:"none",border:"none",color:"#64748b",cursor:"pointer",fontSize:13,fontWeight:800,flexShrink:0}}>×</button>
    </div>
  );
  return (
    <div style={{background:"#f8fafc",borderRadius:13,padding:"12px 14px",border:"1px solid #e2e8f0",
      display:"flex",alignItems:"center",gap:12,marginBottom:14,...style}}>
      <div style={{width:38,height:38,borderRadius:10,background:"#e2e8f0",display:"flex",
        alignItems:"center",justifyContent:"center",fontWeight:900,fontSize:14,color:"#64748b",flexShrink:0}}>
        {aff.icon}
      </div>
      <div style={{flex:1,cursor:"pointer"}} onClick={onClick}>
        <div style={{fontSize:9,fontWeight:800,color:"#64748b",letterSpacing:.5,marginBottom:2}}>
          {tr("adLabel")}{aff.network?" · "+aff.network:""}
        </div>
        <div style={{fontWeight:700,fontSize:13,color:"#334155"}}>{aff.text}</div>
        <div style={{fontSize:11,color:"#64748b",marginTop:2}}>
          {aff.sub} · <span title="Provisions-Link">Affiliate-Link*</span>
        </div>
      </div>
      <button onClick={()=>setDismissed(true)} aria-label="Werbung ausblenden"
        style={{width:24,height:24,borderRadius:6,background:"none",border:"none",color:"#64748b",
          cursor:"pointer",fontSize:14,fontWeight:800,flexShrink:0}}>×</button>
    </div>
  );
}

/* AdSense-Slot. Rendert nichts, solange ADSENSE_CONFIG.client leer ist.
   Wenn konfiguriert: laedt das adsbygoogle.js-Script einmalig und
   schaltet auf NICHT-personalisierte Anzeigen (TTDSG-/DSGVO-vertraeglich
   ohne separates Consent-Banner). Fuer personalisierte Ads zusaetzlich
   einen Consent-Manager einbinden. */
function AdSenseSlot({ slot, format="auto", style={} }) {
  const { tr } = useT();
  const client = ADSENSE_CONFIG.client;
  const slotId = ADSENSE_CONFIG.slots?.[slot];
  useEffect(() => {
    if (!client || !slotId) return;
    if (!window.__vaAdsenseLoaded) {
      try {
        window.adsbygoogle = window.adsbygoogle || [];
        // Nicht-personalisierte Ads bis ein Consent-Manager da ist
        window.adsbygoogle.requestNonPersonalizedAds = 1;
        const s = document.createElement("script");
        s.src = `https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=${client}`;
        s.crossOrigin = "anonymous";
        s.async = true;
        document.head.appendChild(s);
        window.__vaAdsenseLoaded = true;
      } catch {}
    }
    try { (window.adsbygoogle = window.adsbygoogle || []).push({}); } catch {}
  }, [client, slotId]);
  if (!client || !slotId) return null;
  return (
    <div style={{margin:"12px 0",textAlign:"center",...style}}>
      <div style={{fontSize:9,fontWeight:800,color:"#64748b",letterSpacing:.5,marginBottom:4}}>{tr("adLabel")}</div>
      <ins className="adsbygoogle"
        style={{display:"block",minHeight:90}}
        data-ad-client={client}
        data-ad-slot={slotId}
        data-ad-format={format}
        data-full-width-responsive="true"/>
    </div>
  );
}



