      {tactic?.desc && (
        <div style={{background:"rgba(255,255,255,.06)",borderRadius:14,padding:"12px 16px",color:"#64748b",fontSize:14,textAlign:"center",lineHeight:1.55}}>
          {tactic.desc}
        </div>
      )}
