export default function App() {
  return (
    <ErrorBoundary>
      <ThemeProvider>
        <AppRoot/>
        <VersionBadge/>
      </ThemeProvider>
    </ErrorBoundary>
  );
}
function AppRoot() {
  // Standard immer Deutsch (Vereins-App ist primär deutsch). Nur eine vom Nutzer
  // aktiv gewählte Sprache (im localStorage) überschreibt das – NICHT die Browser-
  // sprache, sonst springt die App auf englisch-eingestellten Geräten auf Englisch.
  const [lang,setLang] = useState(()=> LANG_SWITCHER_ENABLED ? (localStorage.getItem(LANG_KEY)||"de") : "de");
  useEffect(()=>{ applyFontScale(getFontScale()); },[]);
  // Arabisch: komplette Oberflaeche rechts-nach-links spiegeln (Browser
  // uebernimmt das fuer Flex-Layouts automatisch ueber dir="rtl").
  useEffect(()=>{
    try{
      document.documentElement.dir = lang==="ar" ? "rtl" : "ltr";
      document.documentElement.lang = lang;
    }catch{}
  },[lang]);
  return (
    <LangCtx.Provider value={lang in T ? lang : "de"}>
      <AppInner lang={lang} setLang={setLang}/>
    </LangCtx.Provider>
  );
}

function DbTest(){
  const [steps,setSteps]=useState([]);
  const [busy,setBusy]=useState(true);
  const cfg=getConfig();

  const run=async()=>{
    setBusy(true);
    const acc=[];
    const push=(s)=>{ acc.push(s); setSteps([...acc]); };

    // 0) Konfiguration
    if(!cfg?.url || !cfg?.key) {
      push({n:"Konfiguration", ok:false, msg:"Keine Supabase-URL/-Key konfiguriert."});
      setBusy(false); return;
    }
    push({n:"Konfiguration", ok:true, msg:cfg.url});

    // 1) Anonymer Sign-Up
    auth._clear();
    let token=null, userId=null;
    try {
      const r = await fetch(`${cfg.url}/auth/v1/signup`, {
        method:"POST",
        headers:{ "Content-Type":"application/json","apikey":cfg.key },
        body: JSON.stringify({ data:{} })
      });
      const txt = await r.text();
      let d=null; try{ d=JSON.parse(txt); }catch{}
      token = d?.access_token || d?.session?.access_token;
      userId = d?.user?.id || d?.id;
      if(r.ok && token) {
        push({n:"1. Anonymer Sign-Up", ok:true, msg:`user_id=${(userId||"").slice(0,8)}\u2026 token=${token.slice(0,20)}\u2026`});
        auth._save({
          access_token: token,
          refresh_token: d?.refresh_token || d?.session?.refresh_token,
          expires_at: d?.expires_at || d?.session?.expires_at || (Math.floor(Date.now()/1000)+3600),
          user_id: userId, is_member:false,
        });
      } else {
        push({n:"1. Anonymer Sign-Up", ok:false, msg:`HTTP ${r.status} \u2013 ${txt.slice(0,400)}`,
              hint:r.status===422 || /anonymous/i.test(txt) ? "Anonymous Sign-Ins sind im Supabase-Dashboard NICHT aktiviert. Authentication \u2192 Sign In / Up \u2192 'Allow anonymous sign-ins' anschalten." : "Antwort vom Auth-Endpoint unerwartet \u2013 siehe Meldung."});
        setBusy(false); return;
      }
    } catch(e) {
      push({n:"1. Anonymer Sign-Up", ok:false, msg:String((e&&e.message)||e)});
      setBusy(false); return;
    }

    // 2) Vereinscode einl\u00f6sen
    try {
      const r = await fetch(`${cfg.url}/rest/v1/rpc/redeem_code`, {
        method:"POST",
        headers:{ "Content-Type":"application/json","apikey":cfg.key,"Authorization":"Bearer "+token },
        body: JSON.stringify({ p_code: JOIN_CODE })
      });
      const txt = await r.text();
      let ok=null; try{ ok=JSON.parse(txt); }catch{}
      if(r.ok && ok===true) {
        push({n:"2. Vereinscode einl\u00f6sen", ok:true, msg:"redeem_code \u2192 true (Mitgliedschaft eingetragen)"});
        const s=auth._load(); auth._save({ ...(s||{}), is_member:true });
      } else if(r.ok && ok===false) {
        push({n:"2. Vereinscode einl\u00f6sen", ok:false, msg:"redeem_code \u2192 false",
              hint:"Code-Hash in app_secret stimmt nicht zum App-Code. Im SQL-Editor erneut ausf\u00fchren: insert into public.app_secret (id,code_hash) values (1,encode(digest('"+JOIN_CODE+"','sha256'),'hex')) on conflict (id) do update set code_hash = excluded.code_hash;"});
        setBusy(false); return;
      } else {
        push({n:"2. Vereinscode einl\u00f6sen", ok:false, msg:`HTTP ${r.status} \u2013 ${txt.slice(0,400)}`,
              hint:r.status===404 ? "RPC 'redeem_code' nicht gefunden. schema.sql ausf\u00fchren." : "Unerwarteter Status."});
        setBusy(false); return;
      }
    } catch(e) {
      push({n:"2. Vereinscode einl\u00f6sen", ok:false, msg:String((e&&e.message)||e)});
      setBusy(false); return;
    }

    // 3) Lesetest app_data
    try {
      const r = await fetch(`${cfg.url}/rest/v1/app_data?limit=1`, {
        headers:{ "apikey":cfg.key,"Authorization":"Bearer "+token }
      });
      const txt = await r.text();
      if(r.ok) {
        push({n:"3. Lesezugriff app_data", ok:true, msg:`HTTP 200 \u2013 ${txt.slice(0,200)}`});
      } else {
        push({n:"3. Lesezugriff app_data", ok:false, msg:`HTTP ${r.status} \u2013 ${txt.slice(0,400)}`,
              hint:r.status===403 || r.status===401 ? "RLS l\u00e4sst nicht durch \u2013 Policy 'members access app_data' fehlt oder Mitgliedschaft nicht eingetragen." : ""});
        setBusy(false); return;
      }
    } catch(e) {
      push({n:"3. Lesezugriff app_data", ok:false, msg:String((e&&e.message)||e)});
      setBusy(false); return;
    }

    // 4) Schreibtest app_data
    const tkey = SK+"__dbtest", tval={ t: Date.now() };
    try {
      const w = await fetch(`${cfg.url}/rest/v1/app_data`, {
        method:"POST",
        headers:{ "Content-Type":"application/json","apikey":cfg.key,"Authorization":"Bearer "+token,"Prefer":"resolution=merge-duplicates" },
        body: JSON.stringify([{ key:tkey, value:tval, updated_at: new Date().toISOString() }])
      });
      const wtxt = await w.text();
      if(!w.ok) {
        push({n:"4. Schreibzugriff app_data", ok:false, msg:`HTTP ${w.status} \u2013 ${wtxt.slice(0,400)}`,
              hint:"RLS blockiert das Schreiben."});
        setBusy(false); return;
      }
      const rb = await fetch(`${cfg.url}/rest/v1/app_data?key=eq.${tkey}&select=value`, {
        headers:{ "apikey":cfg.key,"Authorization":"Bearer "+token }
      });
      const rtxt = await rb.text();
      let rows=[]; try{ rows=JSON.parse(rtxt); }catch{}
      if(rows[0]?.value?.t===tval.t) {
        push({n:"4. Schreibzugriff app_data", ok:true, msg:"Geschrieben + zur\u00fcckgelesen, Wert stimmt."});
      } else {
        push({n:"4. Schreibzugriff app_data", ok:false, msg:`Wert weicht ab: ${rtxt.slice(0,200)}`});
      }
    } catch(e) {
      push({n:"4. Schreibzugriff app_data", ok:false, msg:String((e&&e.message)||e)});
    }
    setBusy(false);
  };

  useEffect(()=>{ run(); },[]);

  const allOk = steps.length>=5 && steps.every(s=>s.ok);
  const Card=({s})=>(
    <div style={{background:s.ok?"#052e16":"#450a0a",border:`1px solid ${s.ok?"#16a34a":"#dc2626"}`,borderRadius:12,padding:"14px 16px",marginBottom:10}}>
      <div style={{fontSize:14,fontWeight:900,color:s.ok?"#86efac":"#fca5a5",marginBottom:6}}>{s.ok?"\u2713 ":"\u2715 "}{s.n}</div>
      <div style={{fontSize:12.5,lineHeight:1.55,color:s.ok?"#bbf7d0":"#fecaca",wordBreak:"break-word"}}>{s.msg}</div>
      {s.hint && <div style={{marginTop:8,fontSize:12,background:"#0f172a",border:"1px solid #334155",borderRadius:8,padding:"8px 10px",color:"#fbbf24",lineHeight:1.5}}>Hinweis: {s.hint}</div>}
    </div>
  );

  return (<div style={{minHeight:"100dvh",background:"#0f172a",color:"#e2e8f0",padding:"28px 18px",fontFamily:"system-ui,sans-serif"}}>
    <div style={{maxWidth:600,margin:"0 auto"}}>
      <h1 style={{fontSize:22,fontWeight:900,margin:"0 0 4px"}}>Datenbank-Diagnose</h1>
      <p style={{color:"#64748b",fontSize:13,margin:"0 0 18px",lineHeight:1.6}}>Geht den ganzen Auth- und Speicher-Weg Schritt f\u00fcr Schritt durch.</p>
      <div style={{background:"#1e293b",borderRadius:12,padding:"12px 16px",fontSize:13,marginBottom:14}}>
        Projekt: <b>{cfg?.url?.replace("https://","").split(".")[0]||"\u2014"}</b>
      </div>
      {steps.map((s,i)=><Card key={i} s={s}/>)}
      {busy && <div style={{color:"#64748b",margin:"8px 0 14px"}}>Test l\u00e4uft\u2026</div>}
      {!busy && allOk && (
        <div style={{background:"#052e16",border:"1px solid #16a34a",borderRadius:12,padding:"14px 16px",marginBottom:14,fontSize:14,color:"#86efac",fontWeight:800}}>
          Alles gr\u00fcn \u2013 die App ist bereit f\u00fcr echte Speicherung.
        </div>
      )}
      <button onClick={run} disabled={busy} style={{marginTop:4,padding:"12px 18px",borderRadius:10,border:"none",background:"#16a34a",color:"#fff",fontWeight:800,fontSize:14,cursor:busy?"default":"pointer",opacity:busy?.6:1}}>Erneut testen</button>
    </div>
  </div>);
}

function AppInner({lang,setLang}) {
  const [data,setData]    = useState(null);
  useEffect(()=>{ applyAffiliateIds(data&&data.affiliateIds); },[data]);
  const [screen,setScr]   = useState("boot");
  const [visitor,setVisitor] = useState(null); // {eid,club} -> oeffentliche Veranstaltungs-Ansicht
  const [cid,setCid]      = useState(null);
  const [linkTeam,setLinkTeam] = useState(null);
  const [session,setSess] = useState(null);
  const [showSetup,setShowSetup] = useState(false);
  const [showLegal,setShowLegal] = useState(false);
  const [showSuperAdmin,setShowSuperAdmin] = useState(
    ()=>new URLSearchParams(window.location.search).has("superadmin")
  );
  const [logoTaps,setLogoTaps] = useState(0);
  const isMaintenance = localStorage.getItem("va_maintenance")==="1"
    && !new URLSearchParams(window.location.search).has("superadmin");
  const [saveStatus,setSaveStatus] = useState(null); // null | "saving" | "saved" | "local"
  const syncRef  = useRef(null);
  const dataRef  = useRef(null);
  const saveTimer= useRef(null);
  const cidRef   = useRef(null); cidRef.current = cid; // immer aktueller Verein für Schreib-Isolation
  const dataRef2 = dataRef; dataRef2.current = data;    // aktueller Stand für den Offline-Nachtrag

  useEffect(()=>{
    (async()=>{
      // 0) Auth-Warmup: Token + Vereinscode-Mitgliedschaft EINMAL etablieren,
      //    bevor der Nutzer navigiert. Verhindert die "erst Fehler, nach Reload
      //    klappt's"-Race beim ersten Login (403 weil Membership noch nicht da).
      try { await auth.ensureMember(); } catch {}

      // 1) Verzeichnis laden. Cloud-leer (HTTP 200, keine Daten) -> seed initial.
      //    Cloud-Fehler / Auth-Block -> KEIN Seed, sonst werden echte Daten ueberschrieben.
      let dir=null;
      try { dir = await sb.getDirectory(); } catch {}
      if (dir && dir.__cloudEmpty) {
        const seeded = seed();
        try { await sb.set(seeded); } catch {}
        dir = seeded;
      } else if (!dir) {
        // Cloud nicht autorisiert oder offline - leeren Fallback-Stand zeigen,
        // sync versucht es alle 10 s erneut. Nichts in die Cloud schreiben.
        dir = normData({ _v: 14 });
      } else if (dir._v != null && dir._v < 10) {
        // Veralteter Stand - migrieren via Seed.
        const seeded = seed();
        try { await sb.set(seeded); } catch {}
        dir = seeded;
      }
      // Einmalige Migration: aktive Saison auf das aktuelle Label "2026/2027"
      // setzen, falls ein bestehender Verein noch eine aeltere Default-Saison
      // gespeichert hat. Spieler haengen an seasonId (nicht am Label) -> reines
      // Umbenennen, verlustfrei. Per Flag genau einmal, damit kuenftige
      // Saisonwechsel nicht zurueckgesetzt werden.
      if (dir && !dir.__cloudEmpty && !dir._seasonFix2627 && Array.isArray(dir.seasons) && dir.seasons.length) {
        const actId = dir.activeSeason || dir.seasons.find(s=>s.status==="active")?.id || dir.seasons[0]?.id;
        const act = dir.seasons.find(s=>s.id===actId);
        if (act && act.label!=="2026/2027") {
          dir = {...dir, seasons: dir.seasons.map(s=>s.id===actId?{...s,label:"2026/2027"}:s), _seasonFix2627:true};
          try { await sb.set(dir); } catch {}
        }
      }
      // Abgelaufene Veranstaltungen aus dem oeffentlichen Live-Index entfernen
      // (nach Ende des Freischaltfensters -> Archiv).
      if (dir && !dir.__cloudEmpty && Array.isArray(dir.liveEvents) && dir.liveEvents.length) {
        const nowMs=Date.now();
        const keep=dir.liveEvents.filter(e=>{ const u=e&&e.until?Date.parse(e.until):NaN; return !isNaN(u)&&nowMs<=u; });
        if(keep.length!==dir.liveEvents.length){ dir={...dir, liveEvents:keep}; try{ await sb.set(dir); }catch{} }
      }
      // Ungenutzte Test-Vereine automatisch entfernen: NUR Vereine, die das
      // Setup nie abgeschlossen haben (!setupCompleted), älter als 45 Tage sind
      // und seit 45+ Tagen keine Aktivität hatten (oder nie). Echte (eingerichtete
      // oder aktive) Vereine bleiben dadurch immer erhalten.
      if (dir && !dir.__cloudEmpty && Array.isArray(dir.clubs) && dir.clubs.length) {
        const nowMs=Date.now(); const GRACE=45*86400000;
        const stale = iso => { const tt=iso?Date.parse(iso):NaN; return !isNaN(tt) && (nowMs-tt)>GRACE; };
        const abandoned = dir.clubs.filter(c=> c && c.id!=="demo" && !c.setupCompleted && stale(c.createdAt) && (!c.lastActive || stale(c.lastActive)));
        if(abandoned.length){
          const ids=new Set(abandoned.map(c=>c.id));
          dir={...dir, clubs:dir.clubs.filter(c=>!ids.has(c.id))};
          try{ await sb.set(dir); }catch{}
          for(const id of ids){ try{ await sb.dbDelete(sb._clubKey(id)); }catch{} }
        }
      }
      // SuperAdmin braucht alle Daten -> voll laden
      if(new URLSearchParams(window.location.search).has("superadmin")){
        let full=null; try { full=await sb.get(); } catch {}
        setData(refreshDemo(full||dir)); setScr("dir"); return; // screen!=="boot", SuperAdmin-Render greift
      }
      const s=sess.get();
      if(s){
        // Multi-Tenant: noch nicht Mitglied dieses Vereins -> Code-Gate.
        if(MULTI_TENANT && s.cid!=="demo" && !auth.isMemberOf(s.cid)){ setData(refreshDemo(dir)); setCid(s.cid); setScr("joincode"); return; }
        // nur den Verein des angemeldeten Nutzers laden
        let cd=null; try { cd=await sb.getClub(s.cid); } catch {}
        cd = cd||dir; if(s.cid==="demo") cd=refreshDemo(cd);
        // Offline gespeicherte Aenderungen ueberleben auch einen App-Neustart:
        // lokalen Stand zeigen, der Sync traegt ihn gleich in die Cloud nach.
        if (sb.hasPending()) { const loc=localGet(); if (loc) cd=normData(loc); }
        setData(cd); setCid(s.cid); setSess(s); setScr(s.role==="user"?"user":"dash"); return;
      }
      // Direktlink ?club=<slug|id>&team=<id> → Verein laden, dann zur Anmeldung
      const params=new URLSearchParams(window.location.search);
      const clubParam=params.get("club");
      if(clubParam){
        const club=(dir.clubs||[]).find(c=>c.slug===clubParam||c.id===clubParam);
        if(club){
          setCid(club.id);
          const teamParam=params.get("team");
          if(MULTI_TENANT && club.id!=="demo" && !auth.isMemberOf(club.id)){ setData(refreshDemo(dir)); if(teamParam)setLinkTeam(teamParam); setScr("joincode"); return; }
          let cd=null; try { cd=await sb.getClub(club.id); } catch {}
          cd = cd||dir; if(club.id==="demo") cd=refreshDemo(cd);
          setData(cd);
          if(teamParam){ setLinkTeam(teamParam); setScr("flow"); }
          else setScr("role");
          return;
        }
      }
      // Verzeichnis anzeigen (nur leichte Vereinsliste)
      setData(refreshDemo(dir)); setScr("dir");
    })();
    syncRef.current=setInterval(async()=>{
      try {
        // Waehrend eines laufenden Schreibvorgangs - oder kurz danach, bis die
        // Cloud den neuen Stand sicher zurueckliefert - NICHT vom Cloud-Read
        // ueberschreiben. Sonst kann ein frisch angelegter Verein aus dem
        // lokalen Stand fallen und beim naechsten Save aus global.clubs
        // verschwinden (Shard bleibt, Verzeichnis-Eintrag geht verloren).
        if (sb._writing) return;
        // Offene Offline-Aenderungen ZUERST nachtragen - ein Cloud-Read wuerde
        // sie im UI ueberschreiben. sb.set merged 3-wegig gegen den Cloud-Stand.
        if (sb.hasPending() && dataRef.current) {
          await sb.set(dataRef.current, cidRef.current);
          return;
        }
        if (sb._lastWrite?.at && Date.now()-sb._lastWrite.at < 6000) return;
        const cur=cidRef.current;
        const r = cur ? await sb.getClub(cur) : await sb.getDirectory();
        if (sb._writing) return; // Read koennte mit einem zwischenzeitlichen Write kollidieren
        if(r?._v>=12){ const rr=(cur==="demo")?refreshDemo(r):r; setData(p=>JSON.stringify(p)===JSON.stringify(rr)?p:rr); }
      } catch {}
    },10000);
    return()=>clearInterval(syncRef.current);
  },[]);

  const save=useCallback(async next=>{
    setData(next);
    setSaveStatus("saving");
    clearTimeout(saveTimer.current);
    const res = await sb.set(next, cidRef.current);
    setSaveStatus(!getConfig() ? "local" : (res && res.ok) ? "saved" : "error");
    saveTimer.current=setTimeout(()=>setSaveStatus(null),4000);
    return res;
  },[]);

  const login=(role,payload)=>{
    const s={...payload,role,cid}; sess.set(s,true); setSess(s);
    const dev=getDeviceInfo();
    const label=role==="admin"?"Admin-Login":role==="trainer"?"Trainer-Login":role==="helper"?"Helfer-Login":"Eltern-Login";
    trackEventGeo("login", label);
    trackEventGeo("login", label);
    const entry={...createAuditEntry("login",label+": "+(payload.name||role),s),cid};
    const newLog=[...(data.securityLog||[]),
      ...(dev.suspicious?[{...createAuditEntry("new_device","Unbekannte Region: "+dev.lang,s),cid}]:[]),
      entry];
    const nowIso=new Date().toISOString();
    sb.set({...data,
      securityLog:newLog,
      clubs:(data.clubs||[]).map(c=>c.id===cid?{...c,lastActive:nowIso}:c),
    }, cid).catch(()=>{});
    // Admin: Onboarding-Wizard wenn Verein noch leer/unfertig.
    if (role === "admin") {
      const club = (data.clubs||[]).find(c=>c.id===cid);
      const teamCount = (data.teams||[]).filter(t=>t.cid===cid).length;
      const needsOnboarding = !club?.setupCompleted && teamCount === 0;
      setScr(needsOnboarding ? "onboard" : "dash");
    } else {
      setScr(role==="user"?"user":"dash");
    }
  };
  const logout=()=>{
    if(session){const e={...createAuditEntry("logout","Logout: "+(session.name||session.role),session),cid};sb.set({...data,securityLog:[...(data.securityLog||[]),e]}, cid).catch(()=>{});}
    sess.del(); setSess(null); setScr(cid?"role":"dir");
  };

  if(showSetup) return (
    <>
      <style>{CSS}</style>
      <SupabaseSetup
        onDone={()=>setShowSetup(false)}
        onSkip={()=>setShowSetup(false)}
      />
    </>
  );

  if(new URLSearchParams(window.location.search).has("dbtest")) return (<><style>{CSS}</style><DbTest/></>);

  {const _q=new URLSearchParams(window.location.search); if(_q.has("tournament")) return (<><style>{CSS}</style><TournamentPublic eid={_q.get("tournament")} clubParam={_q.get("club")}/></>);}
  {const _q=new URLSearchParams(window.location.search); if(_q.has("offer")) return (<><style>{CSS}</style><OfferPublic offerId={_q.get("offer")}/></>);}

  if(visitor) return (<><style>{CSS}</style><TournamentPublic eid={visitor.eid} clubParam={visitor.club} onBack={()=>setVisitor(null)}/></>);

  if(screen==="boot"||!data) return (
    <div style={{minHeight:"100dvh",display:"flex",alignItems:"center",justifyContent:"center",background:"#0f172a"}}>
      <style>{CSS}</style>
      <div style={{textAlign:"center"}}>
        <div style={{fontSize:60,animation:"pulse 1.5s ease infinite",marginBottom:14}}></div>
        <p style={{color:"#86efac",fontWeight:800,fontSize:17}}>Vereins-App lädt...</p>
        {!getConfig()&&<p style={{color:"rgba(255,255,255,.3)",fontSize:12,marginTop:8}}>Lokaler Speicher aktiv</p>}
      </div>
    </div>
  );

  if(showSuperAdmin) return (<><style>{CSS}</style><SuperAdmin data={data}/></>);

  const activeCl = data.clubs.find(c=>c.id===cid);
  const clTeams  = activeTeamsFor(data,cid);

  return (
    <div>
      <style>{CSS}</style>
      {/* Sprachumschalter auf den Auswahl-/Login-Seiten (oben rechts frei).
          Start, Dashboard und Eltern-Ansicht haben einen eigenen im Header/Sidebar. */}
      {!showLegal && !["dir","dash","user"].includes(screen) && <FloatingLangSwitcher lang={lang} setLang={setLang}/>}
      {}
      {saveStatus&&(
        <div style={{position:"fixed",bottom:20,right:16,zIndex:999,display:"flex",alignItems:"center",gap:7,background:saveStatus==="saved"?"#052e16":saveStatus==="saving"?"#0f172a":saveStatus==="error"?"#450a0a":"#451a03",borderRadius:99,padding:"8px 14px",boxShadow:"0 4px 20px rgba(0,0,0,.3)",border:`1px solid ${saveStatus==="saved"?"#16a34a":saveStatus==="saving"?"#334155":saveStatus==="error"?"#dc2626":"#d97706"}`,fontSize:12,fontWeight:700,color:saveStatus==="saved"?"#86efac":saveStatus==="saving"?"#94a3b8":saveStatus==="error"?"#fca5a5":"#fbbf24"}}>
          {saveStatus==="saving"&&<div style={{width:12,height:12,border:"2px solid rgba(255,255,255,.2)",borderTopColor:"#94a3b8",borderRadius:"50%",animation:"spin .7s linear infinite"}}/>}
          {saveStatus==="saved"&&"* Supabase gespeichert"}
          {saveStatus==="saving"&&"Speichert..."}
          {saveStatus==="local"&&"* Lokal gespeichert"}
          {saveStatus==="error"&&"DB-Speichern fehlgeschlagen \u2013 nicht gespeichert (Details: ?dbtest)"}
        </div>
      )}

      {}
      {(screen==="dir"||screen==="role")&&new URLSearchParams(window.location.search).has("dbsetup")&&(
        <button onClick={()=>setShowSetup(true)}
          style={{position:"fixed",bottom:20,left:16,zIndex:998,display:"flex",alignItems:"center",gap:6,background:getConfig()?"#052e16":"#0f172a",border:`1px solid ${getConfig()?"#16a34a":"rgba(255,255,255,.15)"}`,borderRadius:99,padding:"8px 14px",fontSize:12,fontWeight:700,color:getConfig()?"#86efac":"rgba(255,255,255,.4)",cursor:"pointer",fontFamily:"inherit"}}>
           {getConfig()?"DB verbunden":"Datenbank einrichten"}
        </button>
      )}

      {showLegal&&<LegalPage onBack={()=>setShowLegal(false)} cl={activeCl}/>}
      {!showLegal&&screen==="dir"&&<Directory data={data} lang={lang} setLang={setLang} onLegal={()=>setShowLegal(true)} onVisitorOpen={(eid,club)=>setVisitor({eid,club})} onPick={async id=>{
          const realId = id==="__demo__"?"demo":id;
          setCid(realId);
          // Multi-Tenant: erst Vereinscode-Gate, wenn noch nicht Mitglied.
          if(MULTI_TENANT && realId!=="demo" && !auth.isMemberOf(realId)){ setScr("joincode"); return; }
          let cd=null; try { cd=await sb.getClub(realId); } catch {}
          // Transienter Auth-Fehler? Einmal Mitgliedschaft sichern + erneut laden,
          // damit der Admin nicht mit unvollstaendigen Daten ins Dashboard kommt.
          if(!cd){ try { await (MULTI_TENANT?auth.joinClub(realId):auth.ensureMember()); cd=await sb.getClub(realId); } catch {} }
          if(cd){ setData(realId==="demo"?refreshDemo(cd):cd); }
          setScr("role");
        }} onNewClub={async newClubOrData=>{
          if(newClubOrData.clubs){
            await save(newClubOrData);
            return;
          }
          const next={...data,clubs:[...data.clubs,newClubOrData]};
          const res = await save(next);
          // Schritt 1: Save muss überhaupt ok sein.
          if (!res || !res.ok) {
            const err = res?.error || "unbekannt";
            window.alert("Verein konnte NICHT in der Cloud gespeichert werden.\n\nFehler: "+err+"\n\nBitte URL ?dbtest aufrufen, um zu pruefen woran es liegt.");
            setData(p => p ? {...p, clubs:(p.clubs||[]).filter(c=>c.id!==newClubOrData.id)} : p);
            return;
          }
          // Schritt 2: Cloud-Verifizierung - liest die Directory zurueck
          // und prueft, ob der neue Club wirklich drin ist. Das deckt den Fall ab,
          // dass der POST mit HTTP 200 zurueckkommt, aber der Server gar nicht
          // gespeichert hat (Trigger, RLS-with-check-failure, etc.).
          const verify = await sb.verifyClubInCloud(newClubOrData.id);
          if (!verify.ok) {
            window.alert("Verein wurde scheinbar gespeichert, ist aber NICHT in der Cloud auffindbar.\n\nGrund: "+verify.reason+"\n\nDas ist genau das Problem das du gemeldet hast. Bitte schick einen Screenshot dieser Meldung + ?dbtest-Output.");
            setData(p => p ? {...p, clubs:(p.clubs||[]).filter(c=>c.id!==newClubOrData.id)} : p);
            return;
          }
          // Schritt 3: bestaetigt - Verein ist in Cloud sichtbar.
          setCid(newClubOrData.id);
          setScr("alogin");
        }}/>}
      {screen==="onboard"&&activeCl&&session?.role==="admin"&&<AdminOnboarding data={data} cl={activeCl} cid={cid} save={save} onDone={()=>setScr("dash")}/>}
      {screen==="joincode"&&activeCl&&<ClubJoinGate cl={activeCl} onBack={()=>setScr("dir")} onJoined={async()=>{
          let cd=null; try { cd=await sb.getClub(cid); } catch {}
          if(cd){ setData(cd); }
          setScr("role");
        }}/>}
      {screen==="role"  &&activeCl&&<RolePicker cl={activeCl} onRole={r=>setScr(r==="user"?"flow":r==="trainer"?"tlogin":r==="helper"?"hlogin":"alogin")} onGuest={()=>setScr("guest")} onBack={()=>setScr("dir")}/>}
      {screen==="guest" &&activeCl&&<ClubGuestList cl={activeCl} liveEvents={data.liveEvents||[]} onOpen={(eid,club)=>setVisitor({eid,club})} onBack={()=>setScr("role")}/>}
      {screen==="flow"  &&activeCl&&<UserFlow cl={activeCl} teams={clTeams} players={data.players} playerProfiles={data.playerProfiles||[]} trainers={(data.trainers||[]).filter(t=>t.cid===cid)} preselectTid={linkTeam} onDone={(tid,user)=>login("user",{tid,user})} onBack={()=>setScr(linkTeam?"role":"role")}
        onWaitlist={entry=>{ save({...data, waitlist:[...(data.waitlist||[]), { ...entry, id:uid(), cid:activeCl.id, ts:new Date().toISOString(), status:"open" }]}); }}
        onConsent={(profId,by)=>{ const prof=(data.playerProfiles||[]).find(p=>p.id===profId);
          const next={...data, playerProfiles:(data.playerProfiles||[]).map(p=>p.id===profId?{...p, consentAt:new Date().toISOString(), consentBy:by||"Eltern (App-Anmeldung)"}:p)};
          addAuditLog(next, save, {id:uid(), cid, ts:new Date().toISOString(), type:"consent", device:"Eltern-Gerät", msg:`Einwilligung für ${prof?.name||profId} erteilt durch ${by||"Eltern (App-Anmeldung)"}`}); }}
        onGuestConsent={({tid,name,by})=>{ addAuditLog(data, save, {id:uid(), cid, ts:new Date().toISOString(), type:"consent", device:"Eltern-Gerät", msg:`Einwilligung (Gast ohne Profil) für ${name} erteilt durch ${by||"Eltern"} · Team ${(data.teams||[]).find(tm=>tm.id===tid)?.name||tid}`}); }}
        onSetChildPw={(profId,pw)=>{ save({...data, playerProfiles:(data.playerProfiles||[]).map(p=>p.id===profId?{...p, childPw:hashPw(pw), childPwAt:new Date().toISOString()}:p)}); }}/>}
      {screen==="tlogin"&&activeCl&&<TrainerLogin cl={activeCl} trainers={data.trainers.filter(t=>t.cid===cid&&isActive(t))} teams={(data.teams||[]).filter(tm=>tm.cid===cid)} onLogin={tr=>login("trainer",tr)} onSetTrainerPw={(trId,newHash)=>{ save({...data,trainers:(data.trainers||[]).map(t=>t.id===trId?{...t,pw:newHash,mustChangePw:false,sharedAt:t.sharedAt||new Date().toISOString()}:t)}); }} onBack={()=>setScr("role")}/>}
      {screen==="hlogin"&&activeCl&&<HelperLogin cl={activeCl} helpers={data.helpers||[]} onLogin={h=>login("helper",{...h,cid})} onBack={()=>setScr("role")}/>}
      {screen==="alogin"&&activeCl&&<AdminLogin cl={activeCl} onLogin={a=>login("admin",{...a,cid})} onBack={()=>setScr("role")}/>}
      {screen==="user"  &&session&&activeCl&&<UserHome data={data} session={session} onSave={save} onLogout={logout} lang={lang} setLang={setLang}/>}
      {screen==="dash"  &&session&&activeCl&&<Dashboard data={data} session={session} onSave={save} onLogout={logout} lang={lang} setLang={setLang}/>}
      {/* Sicherheitsnetz: eingeloggt, aber Vereinsdaten (noch) nicht geladen (z.B.
          Cloud kurz nicht erreichbar beim Start). Statt leerer grauer Seite einen
          klaren Hinweis zeigen; der 10s-Sync laedt die Daten automatisch nach. */}
      {(screen==="dash"||screen==="user")&&session&&!activeCl&&(
        <div style={{minHeight:"100dvh",display:"flex",alignItems:"center",justifyContent:"center",background:"#0f172a",padding:24}}>
          <div style={{textAlign:"center",maxWidth:340}}>
            <div style={{fontSize:50,marginBottom:12}}>📡</div>
            <p style={{color:"#86efac",fontWeight:800,fontSize:17,marginBottom:8}}>{T[lang]?.connT??T.de.connT}</p>
            <p style={{color:"rgba(255,255,255,.55)",fontSize:13,lineHeight:1.5,marginBottom:18}}>{T[lang]?.connBody??T.de.connBody}</p>
            <button onClick={()=>window.location.reload()} style={{padding:"11px 22px",borderRadius:11,border:"none",background:"#16a34a",color:"#fff",fontWeight:800,fontSize:14,cursor:"pointer",fontFamily:"inherit"}}>{T[lang]?.connReload??T.de.connReload}</button>
            <button onClick={logout} style={{display:"block",margin:"12px auto 0",padding:"8px 16px",borderRadius:10,border:"1px solid rgba(255,255,255,.2)",background:"transparent",color:"rgba(255,255,255,.6)",fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit"}}>{T[lang]?.connLogout??T.de.connLogout}</button>
          </div>
        </div>
      )}
    </div>
  );
}

const trainer_season_block_injected = true;
